class Solution:
    def minCoins(self, coins: list[int], n: int) -> int:
        min_val = float('inf')
        for i in range(n):
            if coins[i] <= n:
                min_val = min(min_val, n // coins[i] + (n % coins[i] != 0))
        return -1 if min_val == float('inf') else min_val

def main():
    coins = list(map(int, input().split()))
    n = int(input())
    solution = Solution()
    print(solution.minCoins(coins, n))

