class Solution {
 public:
    int minCoins(vector<int>& coins, int n) {
        int min_val = INT_MAX;
        for (int i = 0; i < coins.size(); i++) {
            if (coins[i] <= n) {
                min_val = min(min_val, n / coins[i] + (n % coins[i] != 0));
            }
        }
        return min_val == INT_MAX ? -1 : min_val;
    }
 };

def main():
    coins = vector<int>(5);
    coins[0] = 1;
    coins[1] = 2;
    coins[2] = 5;
    n = 10;
    solution = Solution();
    cout << solution.minCoins(coins, n) << endl;
